const int MAX_ITER = 1000;

uniform vec2 u_res;
uniform vec2 u_center_re;
uniform vec2 u_center_im;
uniform vec2 u_view_height;
uniform int u_mode;
uniform vec2 u_julia_c_re;
uniform vec2 u_julia_c_im;
