vec2 ds(float hi, float lo) { return vec2(hi, lo); }

vec2 dsAdd(vec2 a, vec2 b) {
  float s = a.x + b.x;
  float v = s - a.x;
  float e = (a.x - (s - v)) + (b.x - v) + a.y + b.y;
  float hi = s + e;
  return vec2(hi, e - (hi - s));
