<PageLayout name="tropical geometry calculator" back wide>
  <p class="tropical-intro">Work in min-plus tropical arithmetic: <code>a ⊕ b = min(a,b)</code> and <code>a ⊗ b = a + b</code>. Tropical polynomials become lower envelopes of lines.</p>

  <section class="tropical-panel" id="tropical-app">
    <div class="tropical-grid">
      <form class="tropical-card" id="tropical-arithmetic-form">
        <h2>arithmetic</h2>
        <label>
          a
          <input id="tropical-a" type="number" step="any" value="2" />
        </label>
        <label>
          b
          <input id="tropical-b" type="number" step="any" value="5" />
        </label>
        <button class="toolbar-button" type="submit">compute</button>
        <div class="tropical-output" id="tropical-arithmetic-output" aria-live="polite"></div>
      </form>

      <form class="tropical-card" id="tropical-poly-form">
        <h2>polynomial</h2>
        <p class="tropical-note">Coefficients low to high. Example <code>0,3,1</code> means <code>0 ⊕ 3x ⊕ 1x²</code>.</p>
        <label>
          coefficients
          <input id="tropical-coefficients" type="text" value="0,3,1" />
