export {};

type Point = { x: number; y: number };
type Crossing = { i: number; j: number; p: Point; sign: 1 | -1; over: number };

const canvas = document.querySelector<HTMLCanvasElement>("#knot-canvas");
const stats = document.querySelector<HTMLElement>("#knot-stats");
const crossingBox = document.querySelector<HTMLElement>("#knot-crossings");
const polyBox = document.querySelector<HTMLElement>("#knot-polys");
const clearButton = document.querySelector<HTMLButtonElement>("#knot-clear");
const circleButton = document.querySelector<HTMLButtonElement>("#knot-circle");
const trefoilButton = document.querySelector<HTMLButtonElement>("#knot-trefoil");
const r1Button = document.querySelector<HTMLButtonElement>("#knot-r1");
const r2Button = document.querySelector<HTMLButtonElement>("#knot-r2");

const fg = () => getComputedStyle(document.documentElement).getPropertyValue("--fg").trim() || "#181817";
const bg = () => getComputedStyle(document.documentElement).getPropertyValue("--bg").trim() || "#fbfbf9";
const muted = () => getComputedStyle(document.documentElement).getPropertyValue("--muted").trim() || "#77736b";

if (canvas && stats && crossingBox && polyBox && clearButton && circleButton && trefoilButton && r1Button && r2Button) {
  const ctx = canvas.getContext("2d")!;
  let points: Point[] = [];
  let crossings: Crossing[] = [];
  let drawing = false;
  const flipped = new Set<string>();

  function resize() {
    const rect = canvas.getBoundingClientRect();
    const dpr = Math.min(window.devicePixelRatio || 1, 2);
    canvas.width = Math.max(1, Math.floor(rect.width * dpr));
    canvas.height = Math.max(1, Math.floor(rect.height * dpr));
    draw();
  }

  function pointer(event: PointerEvent): Point {
    const rect = canvas.getBoundingClientRect();
    return {
      x: ((event.clientX - rect.left) / rect.width) * canvas.width,
      y: ((event.clientY - rect.top) / rect.height) * canvas.height,
    };
  }

  const sub = (a: Point, b: Point) => ({ x: a.x - b.x, y: a.y - b.y });
  const cross = (a: Point, b: Point) => a.x * b.y - a.y * b.x;
  const dist = (a: Point, b: Point) => Math.hypot(a.x - b.x, a.y - b.y);
  const key = (i: number, j: number) => `${Math.min(i, j)}:${Math.max(i, j)}`;

  function segmentIntersection(a: Point, b: Point, c: Point, d: Point): Point | null {
    const r = sub(b, a);
    const s = sub(d, c);
    const den = cross(r, s);
    if (Math.abs(den) < 1e-6) return null;
    const u = cross(sub(c, a), r) / den;
    const t = cross(sub(c, a), s) / den;
    if (t <= 0.02 || t >= 0.98 || u <= 0.02 || u >= 0.98) return null;
    return { x: a.x + t * r.x, y: a.y + t * r.y };
  }

  function computeCrossings() {
    crossings = [];
    const n = points.length;
    if (n < 4) return;
    for (let i = 0; i < n; i += 1) {
      const a = points[i];
      const b = points[(i + 1) % n];
      for (let j = i + 2; j < n; j += 1) {
        if (i === 0 && j === n - 1) continue;
        const c = points[j];
        const d = points[(j + 1) % n];
        const p = segmentIntersection(a, b, c, d);
        if (!p) continue;
        const sign = cross(sub(b, a), sub(d, c)) > 0 ? 1 : -1;
        const over = flipped.has(key(i, j)) ? j : i;
        crossings.push({ i, j, p, sign, over });
      }
    }
  }

  function simplifyByAngle(threshold: number) {
    if (points.length < 8) return;
    points = points.filter((point, index) => {
      const prev = points[(index - 1 + points.length) % points.length];
      const next = points[(index + 1) % points.length];
      const area = Math.abs(cross(sub(point, prev), sub(next, point)));
      return area / Math.max(1, dist(prev, point) + dist(point, next)) > threshold;
    });
    draw();
  }

  function r2Simplify() {
    computeCrossings();
    if (crossings.length < 2) return;
    const pair = crossings.find((a, index) => crossings.slice(index + 1).some((b) => a.sign !== b.sign && dist(a.p, b.p) < 90));
    if (!pair) return simplifyByAngle(2);
    points = points.filter((_point, index) => Math.abs(index - pair.i) > 1 && Math.abs(index - pair.j) > 1);
    draw();
  }

  function drawPath() {
    if (points.length < 2) return;
    ctx.lineCap = "round";
    ctx.lineJoin = "round";
    ctx.lineWidth = 5;
    ctx.strokeStyle = fg();
    ctx.beginPath();
    ctx.moveTo(points[0].x, points[0].y);
    points.slice(1).forEach((p) => ctx.lineTo(p.x, p.y));
    if (!drawing && points.length > 2) ctx.closePath();
    ctx.stroke();
  }

  function drawCrossings() {
    ctx.font = `${12 * (window.devicePixelRatio || 1)}px monospace`;
    crossings.forEach((crossing, index) => {
      ctx.save();
      ctx.strokeStyle = bg();
      ctx.lineWidth = 12;
      const a = points[crossing.over];
      const b = points[(crossing.over + 1) % points.length];
      const v = sub(b, a);
      const len = Math.hypot(v.x, v.y) || 1;
      ctx.beginPath();
      ctx.moveTo(crossing.p.x - (v.x / len) * 14, crossing.p.y - (v.y / len) * 14);
      ctx.lineTo(crossing.p.x + (v.x / len) * 14, crossing.p.y + (v.y / len) * 14);
      ctx.stroke();
      ctx.strokeStyle = fg();
      ctx.lineWidth = 5;
      ctx.stroke();
      ctx.fillStyle = crossing.sign > 0 ? fg() : muted();
      ctx.fillText(String(index + 1), crossing.p.x + 8, crossing.p.y - 8);
      ctx.restore();
    });
  }

  function polynomialText() {
    const writhe = crossings.reduce((sum, c) => sum + c.sign, 0);
    const pos = crossings.filter((c) => c.sign > 0).length;
    const neg = crossings.length - pos;
    const wrPoly = crossings.map((c, i) => `${c.sign > 0 ? "+" : "-"}t^${i + 1}`).join(" ").replace(/^\+/, "") || "0";
    const bracket = crossings.length === 0 ? "1" : `(-A^3)^-${writhe} · (A^${pos - neg} + ${crossings.length}A^${writhe})`;
    return `<div>W(t) = ${wrPoly}</div><div>writhe-normalized bracket sketch = ${bracket}</div>`;
  }

  function updateReadout() {
    const writhe = crossings.reduce((sum, c) => sum + c.sign, 0);
    stats.innerHTML = `<dt>components</dt><dd>1</dd><dt>vertices</dt><dd>${points.length}</dd><dt>crossings</dt><dd>${crossings.length}</dd><dt>writhe</dt><dd>${writhe}</dd><dt>linking number</dt><dd>0</dd>`;
    crossingBox.innerHTML = crossings.length === 0 ? "no crossings" : crossings.map((c, i) => `<div class="knot-crossing-row"><span>#${i + 1}: segments ${c.i}/${c.j}</span><span>${c.sign > 0 ? "+" : "−"}, over ${c.over}</span></div>`).join("");
    polyBox.innerHTML = polynomialText();
  }

  function draw() {
    computeCrossings();
    ctx.fillStyle = bg();
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    drawPath();
    drawCrossings();
    updateReadout();
  }

  function setCircle() {
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const r = Math.min(canvas.width, canvas.height) * 0.32;
    points = Array.from({ length: 96 }, (_unused, i) => ({ x: cx + Math.cos((i / 96) * Math.PI * 2) * r, y: cy + Math.sin((i / 96) * Math.PI * 2) * r }));
    flipped.clear();
    draw();
  }

  function setTrefoil() {
    const cx = canvas.width / 2;
    const cy = canvas.height / 2;
    const s = Math.min(canvas.width, canvas.height) * 0.17;
    points = Array.from({ length: 220 }, (_unused, i) => {
      const t = (i / 220) * Math.PI * 2;
      return { x: cx + s * Math.sin(t) + 2 * s * Math.sin(2 * t), y: cy + s * Math.cos(t) - 2 * s * Math.cos(2 * t) };
    });
    flipped.clear();
    draw();
  }

  canvas.addEventListener("pointerdown", (event) => {
    drawing = true;
    points = [pointer(event)];
    flipped.clear();
    canvas.setPointerCapture(event.pointerId);
    draw();
  });

  canvas.addEventListener("pointermove", (event) => {
    if (!drawing) return;
    const p = pointer(event);
    if (dist(points[points.length - 1], p) > 5) points.push(p);
    draw();
  });

  canvas.addEventListener("pointerup", () => { drawing = false; draw(); });
  canvas.addEventListener("click", (event) => {
    if (drawing) return;
    const p = pointer(event as PointerEvent);
    const nearest = crossings.find((c) => dist(c.p, p) < 18 * (window.devicePixelRatio || 1));
    if (nearest) flipped.has(key(nearest.i, nearest.j)) ? flipped.delete(key(nearest.i, nearest.j)) : flipped.add(key(nearest.i, nearest.j));
    draw();
  });

  clearButton.addEventListener("click", () => { points = []; flipped.clear(); draw(); });
  circleButton.addEventListener("click", setCircle);
  trefoilButton.addEventListener("click", setTrefoil);
  r1Button.addEventListener("click", () => simplifyByAngle(3.5));
  r2Button.addEventListener("click", r2Simplify);
  window.addEventListener("resize", resize);
  resize();
  setTrefoil();
}

export {};

type Convergent = { n: number; a: number; p: bigint; q: bigint; value: number; error: number };

const form = document.querySelector<HTMLFormElement>("#cf-form");
const kind = document.querySelector<HTMLSelectElement>("#cf-kind");
const rationalFields = document.querySelector<HTMLElement>(".cf-rational-fields");
const quadraticFields = document.querySelector<HTMLElement>(".cf-quadratic-fields");
const summary = document.querySelector<HTMLElement>("#cf-summary");
const table = document.querySelector<HTMLTableElement>("#cf-table");
const errorPlot = document.querySelector<SVGSVGElement>("#cf-error-plot");
const intervals = document.querySelector<SVGSVGElement>("#cf-intervals");

const input = (id: string) => document.querySelector<HTMLInputElement>(id)!;
const esc = (s: string) => s.replace(/[&<>"]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", "\"": "&quot;" })[c]!);

if (form && kind && rationalFields && quadraticFields && summary && table && errorPlot && intervals) {
  const pInput = input("#cf-p");
  const qInput = input("#cf-q");
  const aInput = input("#cf-a");
  const bInput = input("#cf-b");
  const dInput = input("#cf-d");
  const cInput = input("#cf-c");
  const termsInput = input("#cf-terms");

  function gcd(a: bigint, b: bigint): bigint {
    a = a < 0n ? -a : a;
    b = b < 0n ? -b : b;
    while (b) [a, b] = [b, a % b];
    return a || 1n;
  }

  function rationalCf(p: bigint, q: bigint): number[] {
    const terms: number[] = [];
    if (q === 0n) return [0];
    if (q < 0n) { p = -p; q = -q; }
    while (q !== 0n && terms.length < 200) {
      let a = p / q;
      let r = p % q;
      if (r < 0n) { a -= 1n; r += q; }
      terms.push(Number(a));
      p = q;
      q = r;
    }
    return terms;
  }

  function numericCf(value: number, limit: number): number[] {
    const terms: number[] = [];
    let x = value;
    for (let i = 0; i < limit; i += 1) {
      const a = Math.floor(x);
      terms.push(a);
      const frac = x - a;
      if (Math.abs(frac) < 1e-13) break;
      x = 1 / frac;
      if (!Number.isFinite(x)) break;
    }
    return terms;
  }

  function convergents(cf: number[], target: number): Convergent[] {
    let p0 = 0n, p1 = 1n;
    let q0 = 1n, q1 = 0n;
    return cf.map((a, n) => {
      const bigA = BigInt(a);
      const p = bigA * p1 + p0;
      const q = bigA * q1 + q0;
      [p0, p1] = [p1, p];
      [q0, q1] = [q1, q];
      const value = Number(p) / Number(q);
      return { n, a, p, q, value, error: Math.abs(value - target) };
    });
  }

  function fractionText(p: bigint, q: bigint): string {
    const g = gcd(p, q);
    p /= g; q /= g;
    if (q < 0n) { p = -p; q = -q; }
    return q === 1n ? String(p) : `${p}/${q}`;
  }

  function currentValue(): { label: string; value: number; cf: number[] } {
    const limit = Math.max(1, Math.min(80, Number(termsInput.value) || 24));
    if (kind.value === "rational") {
      const p = BigInt(Math.trunc(Number(pInput.value) || 0));
      const q = BigInt(Math.trunc(Number(qInput.value) || 1));
      const value = Number(p) / Number(q || 1n);
      return { label: fractionText(p, q || 1n), value, cf: rationalCf(p, q || 1n).slice(0, limit) };
    }
    const a = Number(aInput.value) || 0;
    const b = Number(bInput.value) || 0;
    const d = Math.max(0, Number(dInput.value) || 0);
    const c = Number(cInput.value) || 1;
    const value = (a + b * Math.sqrt(d)) / c;
    return { label: `(${a} + ${b}√${d}) / ${c}`, value, cf: numericCf(value, limit) };
  }

  function drawError(rows: Convergent[]) {
    const w = 900, h = 220, pad = 30;
    const finite = rows.filter((r) => r.error > 0 && Number.isFinite(r.error));
    const maxLog = finite.length ? Math.max(...finite.map((r) => Math.log10(r.error))) : 0;
    const minLog = finite.length ? Math.min(...finite.map((r) => Math.log10(r.error))) : -1;
    const x = (i: number) => pad + (i / Math.max(1, rows.length - 1)) * (w - 2 * pad);
    const y = (err: number) => h - pad - ((Math.log10(Math.max(err, 1e-18)) - minLog) / Math.max(1e-9, maxLog - minLog)) * (h - 2 * pad);
    const path = rows.map((r, i) => `${i ? "L" : "M"}${x(i)},${y(r.error)}`).join(" ");
    errorPlot.innerHTML = `<line class="cf-axis" x1="${pad}" y1="${h - pad}" x2="${w - pad}" y2="${h - pad}"/><line class="cf-axis" x1="${pad}" y1="${pad}" x2="${pad}" y2="${h - pad}"/><path class="cf-line" d="${path}"/>${rows.map((r, i) => `<circle class="cf-mark" cx="${x(i)}" cy="${y(r.error)}" r="3"/>`).join("")}<text class="cf-muted" x="${pad + 4}" y="20">log₁₀ error</text>`;
  }

  function drawIntervals(rows: Convergent[], target: number) {
    const w = 900, h = 260, pad = 36;
    const pairs = rows.slice(1, 13).map((r, i) => [rows[i].value, r.value] as [number, number]);
    const values = pairs.flat().concat(target);
    const min = Math.min(...values);
    const max = Math.max(...values);
    const scale = (v: number) => pad + ((v - min) / Math.max(1e-12, max - min)) * (w - 2 * pad);
    intervals.innerHTML = `<line class="cf-axis" x1="${pad}" y1="24" x2="${w - pad}" y2="24"/><circle class="cf-mark" cx="${scale(target)}" cy="24" r="5"/><text class="cf-muted" x="${scale(target) + 8}" y="28">target</text>${pairs.map(([a, b], i) => {
      const y = 52 + i * 16;
      return `<line class="cf-line" x1="${scale(Math.min(a, b))}" y1="${y}" x2="${scale(Math.max(a, b))}" y2="${y}"/><text class="cf-muted" x="8" y="${y + 4}">${i + 1}</text>`;
    }).join("")}`;
  }

  function render() {
    rationalFields.hidden = kind.value !== "rational";
    quadraticFields.hidden = kind.value !== "quadratic";
    const { label, value, cf } = currentValue();
    const rows = convergents(cf, value);
    summary.innerHTML = `<div>x = ${esc(label)} ≈ ${value.toPrecision(14)}</div><div>[${cf.slice(0, 24).join(", ")}${cf.length > 24 ? ", …" : ""}]</div>`;
    table.innerHTML = `<thead><tr><th>n</th><th>aₙ</th><th>pₙ/qₙ</th><th>decimal</th><th>|error|</th></tr></thead><tbody>${rows.map((r) => `<tr><td>${r.n}</td><td>${r.a}</td><td>${r.p}/${r.q}</td><td>${r.value.toPrecision(12)}</td><td>${r.error.toExponential(3)}</td></tr>`).join("")}</tbody>`;
    drawError(rows);
    drawIntervals(rows, value);
  }

  form.addEventListener("submit", (event) => { event.preventDefault(); render(); });
  kind.addEventListener("change", render);
  form.addEventListener("input", render);
  render();
}

