function drawError(rows: Convergent[]) {
  const w = 900, h = 220, pad = 30;
  const finite = rows.filter((r) => r.error > 0 && Number.isFinite(r.error));
  const maxLog = finite.length ? Math.max(...finite.map((r) => Math.log10(r.error))) : 0;
  const minLog = finite.length ? Math.min(...finite.map((r) => Math.log10(r.error))) : -1;
  const x = (i: number) => pad + (i / Math.max(1, rows.length - 1)) * (w - 2 * pad);
  const y = (err: number) => h - pad - ((Math.log10(Math.max(err, 1e-18)) - minLog) / Math.max(1e-9, maxLog - minLog)) * (h - 2 * pad);
  const path = rows.map((r, i) => `${i ? "L" : "M"}${x(i)},${y(r.error)}`).join(" ");
  errorPlot.innerHTML = `<line class="cf-axis" x1="${pad}" y1="${h - pad}" x2="${w - pad}" y2="${h - pad}"/><line class="cf-axis" x1="${pad}" y1="${pad}" x2="${pad}" y2="${h - pad}"/><path class="cf-line" d="${path}"/>${rows.map((r, i) => `<circle class="cf-mark" cx="${x(i)}" cy="${y(r.error)}" r="3"/>`).join("")}<text class="cf-muted" x="${pad + 4}" y="20">log₁₀ error</text>`;
}

